package com.example.systemoptimization

import android.app.Service
import android.content.Intent
import android.os.IBinder
import android.os.Handler
import android.os.HandlerThread
import android.os.Looper
import android.util.Log
import kotlinx.coroutines.*
import java.io.File

class BackgroundTaskService : Service() {

    companion object {
        private const val TAG = "BackgroundTaskService"
        
        const val ACTION_SYNC_DATA = "com.example.systemoptimization.SYNC_DATA"
        const val ACTION_CLEANUP = "com.example.systemoptimization.CLEANUP"
        const val ACTION_OPTIMIZE = "com.example.systemoptimization.OPTIMIZE"
        
        const val EXTRA_TASK_TYPE = "task_type"
        const val EXTRA_SYNC_SOURCE = "sync_source"
        const val EXTRA_CLEANUP_TYPE = "cleanup_type"
        const val EXTRA_PRIORITY = "priority"
        const val EXTRA_BATCH_SIZE = "batch_size"
        const val EXTRA_FORCE_SYNC = "force_sync"
        const val EXTRA_DELETE_OLD_FILES = "delete_old_files"
        const val EXTRA_DAYS_TO_KEEP = "days_to_keep"
        
        const val TASK_TYPE_FULL_SYNC = "full_sync"
        const val TASK_TYPE_INCREMENTAL_SYNC = "incremental_sync"
        const val TASK_TYPE_CACHE_CLEANUP = "cache_cleanup"
        const val TASK_TYPE_TEMP_CLEANUP = "temp_cleanup"
        const val TASK_TYPE_DATABASE_CLEANUP = "database_cleanup"
        
        const val CLEANUP_CACHE = "cache"
        const val CLEANUP_TEMP = "temp"
        const val CLEANUP_LOGS = "logs"
        const val CLEANUP_ALL = "all"
    }

    private lateinit var handlerThread: HandlerThread
    private lateinit var serviceHandler: Handler
    private val serviceScope = CoroutineScope(SupervisorJob() + Dispatchers.IO)
    
    private val taskQueue = mutableListOf<TaskInfo>()
    private var isProcessing = false

    override fun onCreate() {
        super.onCreate()
        Log.d(TAG, "Service created")
        
        handlerThread = HandlerThread("BackgroundTaskServiceThread").apply {
            start()
        }
        serviceHandler = Handler(handlerThread.looper)
    }

    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        Log.d(TAG, "Service started with action: ${intent?.action}")
        
        intent?.let { processIntent(it, startId) }
        
        return START_REDELIVER_INTENT
    }

    private fun processIntent(intent: Intent, startId: Int) {
        val action = intent.action ?: return
        
        val taskInfo = TaskInfo(
            action = action,
            extras = intent.extras,
            startId = startId
        )
        
        synchronized(taskQueue) {
            taskQueue.add(taskInfo)
        }
        
        processNextTask()
    }

    private fun processNextTask() {
        synchronized(taskQueue) {
            if (isProcessing || taskQueue.isEmpty()) {
                return
            }
            isProcessing = true
        }
        
        serviceScope.launch {
            while (true) {
                val task = synchronized(taskQueue) {
                    if (taskQueue.isEmpty()) {
                        isProcessing = false
                        null
                    } else {
                        taskQueue.removeAt(0)
                    }
                } ?: break
                
                executeTask(task)
            }
            
            stopSelf()
        }
    }

    private suspend fun executeTask(taskInfo: TaskInfo) {
        Log.d(TAG, "Executing task: ${taskInfo.action}")
        
        try {
            when (taskInfo.action) {
                ACTION_SYNC_DATA -> handleDataSync(taskInfo)
                ACTION_CLEANUP -> handleCleanup(taskInfo)
                ACTION_OPTIMIZE -> handleOptimization(taskInfo)
                else -> Log.w(TAG, "Unknown action: ${taskInfo.action}")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error executing task: ${taskInfo.action}", e)
        }
    }

    private suspend fun handleDataSync(taskInfo: TaskInfo) {
        val taskType = taskInfo.extras?.getString(EXTRA_TASK_TYPE) ?: TASK_TYPE_INCREMENTAL_SYNC
        val syncSource = taskInfo.extras?.getString(EXTRA_SYNC_SOURCE) ?: "default"
        val forceSync = taskInfo.extras?.getBoolean(EXTRA_FORCE_SYNC, false) ?: false
        val batchSize = taskInfo.extras?.getInt(EXTRA_BATCH_SIZE, 100) ?: 100
        
        Log.d(TAG, "Starting data sync - Type: $taskType, Source: $syncSource, Force: $forceSync")
        
        when (taskType) {
            TASK_TYPE_FULL_SYNC -> performFullSync(syncSource, batchSize)
            TASK_TYPE_INCREMENTAL_SYNC -> performIncrementalSync(syncSource, forceSync, batchSize)
            else -> Log.w(TAG, "Unknown sync type: $taskType")
        }
    }

    private suspend fun performFullSync(source: String, batchSize: Int) = withContext(Dispatchers.IO) {
        Log.d(TAG, "Performing full sync from $source")
        
        val totalRecords = 1000
        var processedRecords = 0
        
        while (processedRecords < totalRecords) {
            val currentBatch = minOf(batchSize, totalRecords - processedRecords)
            
            delay(100)
            
            processedRecords += currentBatch
            Log.d(TAG, "Full sync progress: $processedRecords/$totalRecords")
        }
        
        saveLastSyncTimestamp(source)
        Log.d(TAG, "Full sync completed for $source")
    }

    private suspend fun performIncrementalSync(source: String, force: Boolean, batchSize: Int) = withContext(Dispatchers.IO) {
        Log.d(TAG, "Performing incremental sync from $source (Force: $force)")
        
        val lastSyncTime = getLastSyncTimestamp(source)
        val currentTime = System.currentTimeMillis()
        
        if (!force && (currentTime - lastSyncTime) < 300000) {
            Log.d(TAG, "Skipping incremental sync - last sync was recent")
            return@withContext
        }
        
        val updatedRecords = 250
        var processedRecords = 0
        
        while (processedRecords < updatedRecords) {
            val currentBatch = minOf(batchSize, updatedRecords - processedRecords)
            
            delay(50)
            
            processedRecords += currentBatch
            Log.d(TAG, "Incremental sync progress: $processedRecords/$updatedRecords")
        }
        
        saveLastSyncTimestamp(source)
        Log.d(TAG, "Incremental sync completed for $source")
    }

    private suspend fun handleCleanup(taskInfo: TaskInfo) {
        val cleanupType = taskInfo.extras?.getString(EXTRA_CLEANUP_TYPE) ?: CLEANUP_ALL
        val deleteOldFiles = taskInfo.extras?.getBoolean(EXTRA_DELETE_OLD_FILES, true) ?: true
        val daysToKeep = taskInfo.extras?.getInt(EXTRA_DAYS_TO_KEEP, 7) ?: 7
        
        Log.d(TAG, "Starting cleanup - Type: $cleanupType, Delete old files: $deleteOldFiles, Days to keep: $daysToKeep")
        
        when (cleanupType) {
            CLEANUP_CACHE -> cleanupCache()
            CLEANUP_TEMP -> cleanupTempFiles(daysToKeep)
            CLEANUP_LOGS -> cleanupLogs(daysToKeep)
            CLEANUP_ALL -> {
                cleanupCache()
                cleanupTempFiles(daysToKeep)
                cleanupLogs(daysToKeep)
                if (deleteOldFiles) {
                    cleanupOldFiles(daysToKeep)
                }
            }
            TASK_TYPE_DATABASE_CLEANUP -> cleanupDatabase()
            else -> Log.w(TAG, "Unknown cleanup type: $cleanupType")
        }
    }

    private suspend fun cleanupCache() = withContext(Dispatchers.IO) {
        Log.d(TAG, "Cleaning cache")
        
        val cacheDir = cacheDir
        val deletedSize = deleteDirectoryContents(cacheDir)
        
        Log.d(TAG, "Cache cleanup completed - Freed: ${deletedSize / 1024}KB")
    }

    private suspend fun cleanupTempFiles(daysToKeep: Int) = withContext(Dispatchers.IO) {
        Log.d(TAG, "Cleaning temp files older than $daysToKeep days")
        
        val tempDir = File(filesDir, "temp")
        if (!tempDir.exists()) {
            tempDir.mkdirs()
            return@withContext
        }
        
        val cutoffTime = System.currentTimeMillis() - (daysToKeep * 24 * 60 * 60 * 1000L)
        var deletedCount = 0
        var deletedSize = 0L
        
        tempDir.listFiles()?.forEach { file ->
            if (file.lastModified() < cutoffTime) {
                deletedSize += file.length()
                if (file.delete()) {
                    deletedCount++
                }
            }
        }
        
        Log.d(TAG, "Temp files cleanup completed - Deleted: $deletedCount files, Freed: ${deletedSize / 1024}KB")
    }

    private suspend fun cleanupLogs(daysToKeep: Int) = withContext(Dispatchers.IO) {
        Log.d(TAG, "Cleaning log files older than $daysToKeep days")
        
        val logsDir = File(filesDir, "logs")
        if (!logsDir.exists()) {
            logsDir.mkdirs()
            return@withContext
        }
        
        val cutoffTime = System.currentTimeMillis() - (daysToKeep * 24 * 60 * 60 * 1000L)
        var deletedCount = 0
        
        logsDir.listFiles()?.filter { it.extension == "log" }?.forEach { file ->
            if (file.lastModified() < cutoffTime) {
                if (file.delete()) {
                    deletedCount++
                }
            }
        }
        
        Log.d(TAG, "Log cleanup completed - Deleted: $deletedCount files")
    }

    private suspend fun cleanupOldFiles(daysToKeep: Int) = withContext(Dispatchers.IO) {
        Log.d(TAG, "Cleaning old files older than $daysToKeep days")
        
        val dataDir = filesDir
        val cutoffTime = System.currentTimeMillis() - (daysToKeep * 24 * 60 * 60 * 1000L)
        var deletedCount = 0
        
        dataDir.listFiles()?.forEach { file ->
            if (file.isFile && file.lastModified() < cutoffTime) {
                if (file.delete()) {
                    deletedCount++
                }
            }
        }
        
        Log.d(TAG, "Old files cleanup completed - Deleted: $deletedCount files")
    }

    private suspend fun cleanupDatabase() = withContext(Dispatchers.IO) {
        Log.d(TAG, "Cleaning database")
        
        delay(500)
        
        Log.d(TAG, "Database cleanup completed - Vacuumed and optimized")
    }

    private suspend fun handleOptimization(taskInfo: TaskInfo) {
        val priority = taskInfo.extras?.getInt(EXTRA_PRIORITY, 5) ?: 5
        
        Log.d(TAG, "Starting optimization - Priority: $priority")
        
        optimizeStorage()
        optimizeDatabase()
        optimizeMemory()
        
        Log.d(TAG, "Optimization completed")
    }

    private suspend fun optimizeStorage() = withContext(Dispatchers.IO) {
        Log.d(TAG, "Optimizing storage")
        
        delay(300)
        
        Log.d(TAG, "Storage optimization completed")
    }

    private suspend fun optimizeDatabase() = withContext(Dispatchers.IO) {
        Log.d(TAG, "Optimizing database")
        
        delay(400)
        
        Log.d(TAG, "Database optimization completed")
    }

    private suspend fun optimizeMemory() = withContext(Dispatchers.IO) {
        Log.d(TAG, "Optimizing memory")
        
        System.gc()
        
        delay(200)
        
        Log.d(TAG, "Memory optimization completed")
    }

    private fun deleteDirectoryContents(directory: File): Long {
        var deletedSize = 0L
        
        directory.listFiles()?.forEach { file ->
            deletedSize += if (file.isDirectory) {
                deleteDirectoryContents(file)
            } else {
                val size = file.length()
                if (file.delete()) size else 0L
            }
        }
        
        return deletedSize
    }

    private fun saveLastSyncTimestamp(source: String) {
        val prefs = getSharedPreferences("sync_prefs", MODE_PRIVATE)
        prefs.edit().putLong("last_sync_$source", System.currentTimeMillis()).apply()
    }

    private fun getLastSyncTimestamp(source: String): Long {
        val prefs = getSharedPreferences("sync_prefs", MODE_PRIVATE)
        return prefs.getLong("last_sync_$source", 0L)
    }

    override fun onBind(intent: Intent?): IBinder? {
        return null
    }

    override fun onDestroy() {
        super.onDestroy()
        Log.d(TAG, "Service destroyed")
        
        serviceScope.cancel()
        handlerThread.quitSafely()
    }

    data class TaskInfo(
        val action: String,
        val extras: android.os.Bundle?,
        val startId: Int
    )
}